/* =====================================================================
   DATA BOOKS DE DORMENTES — Tabela admin-only + carga inicial CAVAN

   Rode este arquivo no SQL Editor do Supabase do projeto Concreto.

   Origem dos dados iniciais:
   "Cópia de Extração de Dados dos Data Books - Dormentes CAVAN.xlsx"
   Linhas importadas: 210

   Regra de acesso:
   - Apenas usuários com perfil admin em public.usuarios_app podem visualizar,
     criar, editar ou excluir Data books.
   ===================================================================== */

create extension if not exists "pgcrypto";
grant usage on schema public to authenticated;

/* Funções de perfil compatíveis com o sistema principal. */
create table if not exists public.usuarios_app (
  id uuid primary key references auth.users(id) on delete cascade,
  nome text,
  email text not null,
  perfil text not null default 'consulta',
  ativo boolean not null default true,
  criado_em timestamptz not null default now(),
  atualizado_em timestamptz not null default now()
);

create or replace function public.normalizar_perfil(valor text)
returns text
language sql
immutable
as $$
  select case
    when translate(lower(trim(coalesce(valor, ''))), 'áàâãéêíóôõúüç', 'aaaaeeiooouuc') = 'admin' then 'admin'
    when translate(lower(trim(coalesce(valor, ''))), 'áàâãéêíóôõúüç', 'aaaaeeiooouuc') in ('qualidade', 'fiscalizacao') then 'fiscalizacao'
    else 'consulta'
  end;
$$;

create or replace function public.perfil_usuario_atual()
returns text
language sql
stable
security definer
set search_path = public
as $$
  select coalesce((
    select public.normalizar_perfil(u.perfil::text)
    from public.usuarios_app u
    where u.id = auth.uid()
      and u.ativo is true
    limit 1
  ), 'consulta');
$$;

create or replace function public.eh_admin()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select public.perfil_usuario_atual() = 'admin';
$$;

grant execute on function public.normalizar_perfil(text) to authenticated;
grant execute on function public.perfil_usuario_atual() to authenticated;
grant execute on function public.eh_admin() to authenticated;

/* Auditoria unificada. */
create table if not exists public.auditoria_alteracoes (
  id uuid primary key default gen_random_uuid(),
  tabela text not null,
  registro_id uuid,
  acao text not null check (acao in ('INSERT', 'UPDATE', 'DELETE')),
  usuario_id uuid references auth.users(id) on delete set null,
  usuario_nome text,
  usuario_email text,
  valores_antes jsonb,
  valores_depois jsonb,
  criado_em timestamptz not null default now()
);

create index if not exists idx_auditoria_tabela on public.auditoria_alteracoes (tabela);
create index if not exists idx_auditoria_registro_id on public.auditoria_alteracoes (registro_id);
create index if not exists idx_auditoria_criado_em on public.auditoria_alteracoes (criado_em desc);

create or replace function public.preencher_campos_auditoria()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if tg_op = 'INSERT' then
    new.criado_por := coalesce(new.criado_por, auth.uid());
    new.atualizado_por := coalesce(new.atualizado_por, auth.uid());
    new.criado_em := coalesce(new.criado_em, now());
    new.atualizado_em := coalesce(new.atualizado_em, now());
  elsif tg_op = 'UPDATE' then
    new.atualizado_por := auth.uid();
    new.atualizado_em := now();
  end if;
  return new;
end;
$$;

create or replace function public.registrar_auditoria_alteracao()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_usuario_id uuid := auth.uid();
  v_usuario_nome text;
  v_usuario_email text;
  v_registro_id uuid;
begin
  select nome, email
    into v_usuario_nome, v_usuario_email
  from public.usuarios_app
  where id = v_usuario_id
  limit 1;

  if tg_op = 'DELETE' then
    v_registro_id := old.id;
  else
    v_registro_id := new.id;
  end if;

  insert into public.auditoria_alteracoes (
    tabela, registro_id, acao, usuario_id, usuario_nome, usuario_email, valores_antes, valores_depois
  ) values (
    tg_table_name,
    v_registro_id,
    tg_op,
    v_usuario_id,
    v_usuario_nome,
    v_usuario_email,
    case when tg_op in ('UPDATE', 'DELETE') then to_jsonb(old) else null end,
    case when tg_op in ('INSERT', 'UPDATE') then to_jsonb(new) else null end
  );

  if tg_op = 'DELETE' then
    return old;
  end if;
  return new;
end;
$$;

/* Tabela principal de Data books. */
create table if not exists public.data_books_dormentes (
  id uuid primary key default gen_random_uuid(),

  -- Informações Gerais do Lote
  cliente text,
  tipo_dormente text,
  lote text,
  data_producao date,
  lotes_chumbadores text,

  -- Corte de Aço por Bobina
  nota_fiscal text,
  numero_bobina text,
  modulo_elasticidade text,

  -- Concreto / Resistência
  compressao_axial_05_dias text,
  compressao_axial_7_dias text,
  compressao_axial_14_dias text,
  compressao_axial_28_dias text,
  tracao_flexao_14_dias text,
  tracao_flexao_28_dias text,
  transferencia_protensao text,

  -- Acompanhamento de Temperatura
  temperatura_inicio text,
  temperatura_meio text,
  temperatura_fim text,

  -- Ensaio Estático
  momento_positivo_apoio_trilho_kn text,
  momento_negativo_apoio_trilho_kn text,
  momento_negativo_centro_dormente_kn text,
  momento_positivo_centro_dormente_kn text,
  torque_nm text,
  arrancamento_kn text,
  carga_aderencia_kn text,
  deslocamento_fio_aco_mm text,

  -- Rastreabilidade
  fonte text,
  fonte_referencia text,
  origem_planilha_linha integer,
  observacoes text,

  criado_em timestamptz not null default now(),
  atualizado_em timestamptz not null default now(),
  criado_por uuid references auth.users(id) on delete set null,
  atualizado_por uuid references auth.users(id) on delete set null
);

create index if not exists idx_data_books_lote on public.data_books_dormentes (lote);
create index if not exists idx_data_books_cliente on public.data_books_dormentes (cliente);
create index if not exists idx_data_books_tipo_dormente on public.data_books_dormentes (tipo_dormente);
create index if not exists idx_data_books_data_producao on public.data_books_dormentes (data_producao desc);
create index if not exists idx_data_books_numero_bobina on public.data_books_dormentes (numero_bobina);

alter table public.data_books_dormentes enable row level security;
revoke all on table public.data_books_dormentes from anon;
grant select, insert, update, delete on table public.data_books_dormentes to authenticated;

/* Recria policies de forma idempotente. */
drop policy if exists "admin visualiza data books" on public.data_books_dormentes;
create policy "admin visualiza data books"
on public.data_books_dormentes
for select
to authenticated
using (public.eh_admin());

drop policy if exists "admin cria data books" on public.data_books_dormentes;
create policy "admin cria data books"
on public.data_books_dormentes
for insert
to authenticated
with check (public.eh_admin());

drop policy if exists "admin edita data books" on public.data_books_dormentes;
create policy "admin edita data books"
on public.data_books_dormentes
for update
to authenticated
using (public.eh_admin())
with check (public.eh_admin());

drop policy if exists "admin exclui data books" on public.data_books_dormentes;
create policy "admin exclui data books"
on public.data_books_dormentes
for delete
to authenticated
using (public.eh_admin());

/* Triggers de auditoria. */
drop trigger if exists trg_data_books_dormentes_preencher_auditoria on public.data_books_dormentes;
create trigger trg_data_books_dormentes_preencher_auditoria
before insert or update on public.data_books_dormentes
for each row execute function public.preencher_campos_auditoria();

drop trigger if exists trg_data_books_dormentes_registrar_auditoria on public.data_books_dormentes;
create trigger trg_data_books_dormentes_registrar_auditoria
after insert or update or delete on public.data_books_dormentes
for each row execute function public.registrar_auditoria_alteracao();

